VALUES
  ('elementary-d0d1b9a2-moex-00485', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-112-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '甲公司於X1年初購入設備一部，估計可用5年，殘值估計為$3,000，採雙倍餘額遞減法提列折舊及成本 模式衡量，X2年度折舊費用為$10,080，則該設備購入成本為何？', '["$40,800", "$42,000", "$45,000", "$63,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:47+00:00", "source_pdf_sha1": "c5115db7419f", "answer_pdf_sha1": "3f17411e8587", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "507", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00486', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-112-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '下列有關遞耗資產的敘述，何者正確？', '["臺灣的天然資源相對有限故無企業之資產負債表中曾報導過遞耗資產", "遞耗資產的取得成本包含使天然資源達到可以開採狀態的一切必要且合理的支出", "遞耗資產的成本分攤方法須與不動產、廠房及設備的成本分攤方法相同", "遞耗資產的成本分攤不需採用有系統的方式而係由經理人主觀決定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:47+00:00", "source_pdf_sha1": "c5115db7419f", "answer_pdf_sha1": "3f17411e8587", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "507", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00487', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-112-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '公司機器設備提列折舊每年皆採年數合計法，最符合財務報導的何種品質特性？', '["攸關性", "忠實表述", "可比性", "可驗證性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:47+00:00", "source_pdf_sha1": "c5115db7419f", "answer_pdf_sha1": "3f17411e8587", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "507", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00488', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-112-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '甲公司於X1年3月15日以$1,800,000購入一塊上有舊倉庫之土地以供建廠用。X1年4月移除舊倉庫的 成本$70,000、支付給代書包括代書費$18,000 及由代書代付的相關稅費$32,000。拆除舊倉庫之廢料出售 得款$80,000。則甲公司在X1年12月31日之土地帳面金額為：', '["$1,800,000", "$1,840,000", "$1,920,000", "$1,870,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:47+00:00", "source_pdf_sha1": "c5115db7419f", "answer_pdf_sha1": "3f17411e8587", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "507", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00489', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-112-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '甲公司於X1年1月1日買入商辦大樓專供出租使用，購買成本$8,000,000、公司行政成本$60,000、仲介 費$80,000、過戶規費$40,000、不動產移轉稅捐$20,000。甲公司對此不動產擬續後採公允價值模式評價， X1年12月31日該不動產之公允價值為$8,500,000，則甲公司X1年度應認列之公允價值調整利益為何？', '["$300,000", "$360,000", "$440,000", "$500,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:47+00:00", "source_pdf_sha1": "c5115db7419f", "answer_pdf_sha1": "3f17411e8587", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "507", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00490', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-112-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '有關生物資產，下列敘述何者錯誤？', '["自生物資產收成之農產品，應以收成點之公允價值減出售成本衡量之", "農業產品於原始認列後應作為存貨處理", "農業產品於原始認列時所產生之利益應於發生當期計入損益", "將農業產品加工後出售所發生之加工成本為營業費用"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:47+00:00", "source_pdf_sha1": "c5115db7419f", "answer_pdf_sha1": "3f17411e8587", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "507", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00491', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-112-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', 'X1年1月25日甲公司的蛋雞生產雞蛋一批，公允價值為$2,000，運送至市場的運輸成本為$200、出售成 本為$100，X1年1月31日該批雞蛋仍未售出，估計售價為$2,600，完成出售所需之成本為$450，試問甲 公司X1年1月31日應以何金額列示該批雞蛋於資產負債表上？', '["$1,700", "$2,000", "$2,150", "$2,600"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:47+00:00", "source_pdf_sha1": "c5115db7419f", "answer_pdf_sha1": "3f17411e8587", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "507", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00492', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-112-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '下列何者一定不可列入流動負債？', '["銀行透支", "應付帳款", "本期所得稅負債", "待分配股票股利"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:47+00:00", "source_pdf_sha1": "c5115db7419f", "answer_pdf_sha1": "3f17411e8587", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "507", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00493', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-112-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '丙公司出售設備並提供售後服務，依過去經驗估計有5%需要售後服務，其中70%會有小瑕疵，每台平均 約需$3,000之成本；30%會發生重大瑕疵，每台平均約需$5,500之成本。假設今年售出設備8,000台，每 台單價$90,000。銷售當年度實際發生修理費用計$1,000,000，則年底產品保證負債為何？', '["$1,500,000", "$1,000,000", "$500,000", "$0"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:47+00:00", "source_pdf_sha1": "c5115db7419f", "answer_pdf_sha1": "3f17411e8587", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "507", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00494', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-112-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '甲公司於X10年1月1日發行面額$100,000，5年期，利率為7%公司債，每年6月30日及12月31日各 付息一次。若有效利率為8%，公司債之發行價格為$95,945，則該公司X10年12月31日公司債之帳面 金額為：（四捨五入至元）', '["$96,283", "$96,634", "$97,379", "$98,185"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:47+00:00", "source_pdf_sha1": "c5115db7419f", "answer_pdf_sha1": "3f17411e8587", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "507", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL)
